        _row(d, "Dynamic ortho image services on high-latency NAS time out during pan/zoom. CPU is low. What is the first tuning axis before adding hardware?", "Caching, overviews/pyramids, mosaic performance, and storage IOPS—not only horizontal scaling of Portal.", "Delete pyramids to save space.", "Force synchronous drawing for all requests.", "Disable JPEG compression."),
        _row(d, "Notebook Server grants publisher broadly; notebook outputs reference sensitive UNC paths in logs. What control is missing?", "Least privilege on roles, output locations, and share ACLs for the Notebook run-as account—not publisher for all by default.", "Disable logging.", "Store outputs in Portal content only without review.", "Run notebooks as SYSTEM."),
        _row(d, "GeoEvent feed TLS was renewed; the feed shows connected but no rows insert. Password unchanged. What should you verify in the GeoEvent tier?", "Trust for the new server certificate in the GeoEvent/Java trust store and any client-auth settings—not only browser trust.", "Disable TLS on the feed.", "Reinstall Portal.", "Delete the spatiotemporal big data store blindly."),
        _row(d, "Two customer portals mistakenly federate one ArcGIS Server site. Publishing conflicts and ownership issues appear. What is the design fix?", "One portal should own a given Server site pattern; remove unsupported overlapping federation and realign architecture.", "Merge portals by copying directories.", "Share one primary admin across tenants.", "Disable one portal without unfederating."),
        _row(d, "A migration copied portal content directories expecting identical item IDs in a new portal. Web maps break. What principle was violated?", "Item IDs and URLs are portal-specific; use supported export/import or migration tooling—not raw folder copies for item identity.", "Re-use machine names only.", "Delete search index to fix IDs.", "Run two portals on one content dir."),
        _row(d, "SAML logins succeed, but portal roles from AD groups apply to some users and not others in the same group. What should you compare?", "Token group claims, nested group limits, attribute mapping, and what the IdP actually emits for each user—not only AD membership in LDAP.", "Delete custom roles.", "Disable nested groups in AD without IdP change.", "Assume SAML cannot carry groups."),
        _row(d, "Guest Wi-Fi uses captive DNS; Field Maps OAuth fails intermittently while corporate SSID works. What category is this?", "Client network path and DNS to OAuth endpoints; captive portals often block or redirect required hosts.", "A Field Maps bug on iOS only.", "Disable mobile OAuth globally.", "Require VPN for all field staff always."),
        _row(d, "Cloud raster store publishing works from Server node A but not node B in the same site. Same site config. What often differs?", "Per-node IAM/instance profile or credential resolution for the cloud store—not only shared config store.", "Reinstall node B with node A’s hostname.", "Disable multi-machine sites.", "Use only local file GDB."),
        _row(d, "Distributed collaboration is connected, but edits never arrive cross-org. Firewalls allow 443. What beyond connectivity matters?", "Sync direction, schedules, supported item types, and workspace membership—not only initial trust establishment.", "Collaboration is always synchronous.", "Delete and recreate AD users.", "Disable HTTPS on one portal."),
        _row(d, "A UNC data path resolves on an admin laptop drive mapping but not from all Server machines. Services start only on one node. What is the issue class?", "Consistent, service-account-visible paths (UNC with correct ACLs)—not user-specific mappings.", "Copy data to each desktop.", "Use subst drives on servers.", "Disable multi-machine clustering."),
        _row(d, "An HTTP-only widget requests tokens while the site is HTTPS-only; browsers block mixed content. Who must fix what?", "The app must call HTTPS endpoints and follow supported token patterns—mixed content cannot be ‘fixed’ by lowering portal security.", "Disable HTTPS for widgets.", "Set portal to HTTP internally and externally.", "Disable CORS globally."),
        _row(d, "SMTP allows internal relay only; external contractors never receive portal email invites. What is missing?", "A mail path that can deliver to external addresses per org policy—SMTP relay, allowed recipients, or alternative onboarding—not only portal SMTP ‘working’ for internal test.", "Disable email verification.", "Point portal SMTP at an open relay on the internet without authentication or allowlisting.", "Share admin passwords instead."),
        _row(d, "A browser widget uses localhost redirect URIs in production; users fail OAuth after promoting the app. What is wrong?", "Production redirect URIs must be registered for the real hostnames and environments—not dev localhost entries only.", "OAuth allows any redirect automatically.", "Disable OAuth for production.", "Use one client ID without URI list."),
        _row(d, "A second raster analytics Server site is federated; portal lists it, but hosted analytics outputs referencing it fail. What should you verify first?", "Reachability, data store registrations, and credentials for that federated site from the hosting tier—not only portal UI listing.", "Merge both config stores manually.", "Install Portal on the raster server.", "Disable HTTPS on the analytics site."),
        _row(d, "Authorization in Pro shows valid, but Pro claims licensing expired while Portal shows the user licensed. What should you reconcile?", "Named user types, add-ons, and which portal URL Pro signs into—align provisioning and sign-in target.", "Delete all named users.", "Remove Web Adaptor.", "Disable SAML only."),
        _row(d, "A base deployment will expose only 443 externally; internal components use 6443/7443. What pattern matches security guidance?", "Terminate TLS at Web Adaptor or reverse proxy; keep internal ports off the public internet unless architected explicitly.", "Publish 6443 on the public firewall.", "Bind Portal to HTTP only.", "Disable internal HTTPS."),
        _row(d, "Object store is configured yet large hosted attachments still fail. What is a likely gap?", "Object store health, limits, and registration versus expectations for blob size and throughput.", "Raster analytics is missing.", "Only tile cache size matters.", "Portal groups control attachment size."),
        _row(d, "An org enables anonymous access for a dashboard, but layers still prompt for login. What is the usual cause?", "Layer and item sharing must match the app audience across all dependencies—not only the app item.", "HTTPS is optional.", "Anonymous disables all layers automatically.", "Only the print service needs sharing."),
