        _row(t, "Fonts for labels work in Pro but not in a custom print service on Server. Fonts were installed only to the admin profile. Fix?", "Install fonts for all users or the ArcGIS Server account system-wide.", "Remove labels from all maps.", "Print as raster only always.", "Run print as Administrator interactively."),
        _row(t, "MDM-managed Android fails SSL handshake to Portal; iOS works. Custom enterprise CA is in play. What should be fixed on devices?", "Trust store for the portal chain and any inspection CA in the MDM profile—not only browser trust.", "Disable TLS on mobile.", "Use HTTP for Field Maps.", "Delete certificates on Portal."),
        _row(t, "Map image layer shows stale imagery after update; REST cache clear did not help; CDN still serves old tiles. What should you address?", "CDN/proxy cache TTLs, cache busting, or service cache update strategy—not only Server REST cache.", "Delete the service.", "Disable all caching forever.", "Rename the portal URL only."),
        _row(t, "502/504 at Web Adaptor during backups; Server CPU low. What interaction?", "Backup I/O locks or timeouts through the stack; coordinate maintenance windows and backup modes with service health.", "The Web Adaptor host is idle; 502/504 must be a false alarm from load balancer health probes only.", "Disable backups without policy.", "Set all instances to zero."),
